WITH ext AS (
  INSERT INTO appdata.extractions (transcript_id, model, prompt_version, payload)
  VALUES ($1::bigint, $2, 'v1', $3::jsonb)
  RETURNING id
), job AS (
  UPDATE appdata.job_queue SET status = 'done' WHERE id = $4::bigint RETURNING id
), methodologist AS (
  SELECT id FROM appdata.users WHERE role = 'methodologist' AND active ORDER BY id LIMIT 1
), owner AS (
  SELECT owner_user_id FROM appdata.clients WHERE id = $5::bigint
), task AS (
  INSERT INTO appdata.tasks (entity_type, entity_id, assignee_user_id, title, stage_ref)
  VALUES ('transcript', $1::bigint, COALESCE((SELECT id FROM methodologist), (SELECT owner_user_id FROM owner)), 'Zatwierdź analizę AI — opportunity #' || $6::bigint, 'badanie_potrzeb')
  RETURNING id
)
SELECT (SELECT id FROM ext) AS extraction_id, (SELECT id FROM task) AS task_id;

WITH job AS (
  UPDATE appdata.job_queue
  SET status = 'failed', last_error = $2, attempts = attempts + 1
  WHERE id = $1::bigint
  RETURNING id
), owner AS (
  SELECT owner_user_id FROM appdata.clients WHERE id = $4::bigint
), task AS (
  INSERT INTO appdata.tasks (entity_type, entity_id, assignee_user_id, title, stage_ref)
  VALUES ('transcript', $5::bigint, (SELECT owner_user_id FROM owner), 'AI nie zadziałało — uzupełnij ręcznie analizę dla opportunity #' || $3::bigint, 'badanie_potrzeb')
  RETURNING id
)
SELECT (SELECT id FROM job) AS job_id, (SELECT id FROM task) AS task_id;
